import React, { useState } from 'react';

const App = () => {
  const [selectedMethods, setSelectedMethods] = useState([]);
  const [secretKeys, setSecretKeys] = useState({});

  const handleMethodSelect = (method) => {
    if (!selectedMethods.includes(method)) {
      setSelectedMethods([...selectedMethods, method]);
    }
  }

  const handleSubmit = (event) => {
    event.preventDefault();
    console.log(secretKeys);
  }

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white shadow-md rounded-md p-4 max-w-md">
        <h2 className="text-lg font-bold mb-2">Multi-Factor Auth Setup</h2>
        <ul className="list-disc mb-4">
          <li className="mb-2"><button className="bg-[#C06C88] hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded" onClick={() => handleMethodSelect('SMS')}>SMS</button></li>
          <li className="mb-2"><button className="bg-[#C06C88] hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded" onClick={() => handleMethodSelect('Email')}>Email</button></li>
        </ul>
        <form className="mb-4">
          <div className="mb-2"><input className="bg-transparent border border-gray-500 px-2 py-1 rounded" type="text" placeholder="Enter SMS secret key" onChange={(event) => setSecretKeys({ ...secretKeys, sms: event.target.value })} /></div>
          <div className="mb-2"><input className="bg-transparent border border-gray-500 px-2 py-1 rounded" type="text" placeholder="Enter Email secret key" onChange={(event) => setSecretKeys({ ...secretKeys, email: event.target.value })} /></div>
          <button className="bg-[#C06C88] hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded" type="submit" onClick={handleSubmit}>Submit</button>
        </form>
        <div className="bg-[#B7D7CD] p-4 rounded-md mb-4">
          <h3 className="text-lg font-bold mb-2">Selected Methods:</h3>
          <ul className="list-disc mb-4">
            {selectedMethods.map((method, index) => (
              <li key={index} className="mb-2">{method}</li>
            ))}
          </ul>
        </div>
      </div>
    </div>
  );
};

export default App;
